#include <bits/stdc++.h>
using namespace std;
const int N=2000005;
int tr[N],n,c,m,a[N],lst1[N],lst2[N],vis[N],ans[N];
struct node
{
	int l,r,id;
} q[N];
bool cmp(node x,node y)
{
	return x.r<y.r;
}
int lowbit(int x)
{
	return x&-x;
}
void add(int x,int k)
{
	for(int i=x;i<=n;i+=lowbit(i))
	{
		tr[i]+=k;
	}
}
int query(int x)
{
	int ans2=0;
	for(int i=x;i;i-=lowbit(i)) ans2+=tr[i];
	return ans2;
}
int main()
{
	cin>>n>>c>>m;
	for(int i=1;i<=n;i++)
	{
		cin>>a[i];
	}
	for(int i=1;i<=m;i++)
	{
		cin>>q[i].l>>q[i].r;
		q[i].id=i;
	}
	sort(q+1,q+1+m,cmp);
	int pow=1;
	for(int i=1;i<=m;i++)
	{
		for(int j=pow;j<=q[i].r;j++)
		{
			if(lst1[a[j]]==0) lst1[a[j]]=j;
			else
			{
				add(lst1[a[j]],1);
				if(lst2[a[j]]) add(lst2[a[j]],-1);
				lst2[a[j]]=lst1[a[j]];
				lst1[a[j]]=j;
			}
		}
		pow=q[i].r+1;
		ans[q[i].id]=query(q[i].r)-query(q[i].l-1);
	 } 
	 for(int i=1;i<=m;i++) cout<<ans[i]<<'\n';
	 return 0; 
}
